+      if (/^### Done$/i.test(line)) {
+        inDone = true;
+        continue;
+      }
+      if (/^### /i.test(line)) {
+        inDone = false;
+        continue;
+      }
+      if (!inDone) continue;
+      const matches = [...line.matchAll(/#(\d+)/g)];
+      for (const match of matches) {
+        const key = `#${match[1]}`;
+        if (!result.has(key)) result.set(key, []);
+        result.get(key).push(agent);
+      }
+    }
+  }
